@page "/book-appointment"
@rendermode InteractiveServer
@using sv_acd790ad33114483a7a38179acda1a9f.Services
@inject IAppointmentService AppointmentService

<h3>Book an Appointment</h3>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* STEP 1 *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label>Patient Name</label>
            <InputText @bind-Value="model.PatientName" class="form-control" />
            <ValidationMessage For="() => model.PatientName" />
        </div>

        <div class="mb-3">
            <label>Email</label>
            <InputText @bind-Value="model.Email" class="form-control" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label>Phone</label>
            <InputText @bind-Value="model.Phone" class="form-control" />
            <ValidationMessage For="() => model.Phone" />
        </div>

        <div class="mb-3">
            <label>Insurance Provider</label>
            <InputSelect @bind-Value="model.InsuranceProvider" class="form-control">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="CheckAvailability">
                Check Availability
            </button>
        }
    </fieldset>

    @* STEP 2 *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label>Preferred Doctor</label>
                <InputSelect @bind-Value="model.Doctor" class="form-control" @bind:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doctor in doctors)
                    {
                        <option value="@doctor">@doctor</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.Doctor" />
            </div>

            <div class="mb-3">
                <label>Date</label>
                <InputDate @bind-Value="model.AppointmentDate" class="form-control" @bind:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => model.AppointmentDate" />
                @if (model.AppointmentDate.HasValue && model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
                {
                    <div class="validation-message">Date must be in the future.</div>
                }
            </div>

            <div class="mb-3">
                <label>Time Slot</label>
                <InputSelect @bind-Value="model.TimeSlot" class="form-control">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label>Reason for Visit</label>
                <InputTextArea @bind-Value="model.Reason" class="form-control" rows="4" />
                <ValidationMessage For="() => model.Reason" />
            </div>

            <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                @(isSubmitting ? "Booking..." : "Book Appointment")
            </button>
        </fieldset>
    }
</EditForm>

@if (bookingConfirmed)
{
    <div class="alert alert-success mt-3">Appointment booked successfully!</div>
}

@code {
    private AppointmentModel model = new();
    private EditContext? editContext;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private bool bookingConfirmed;

    private List<string> doctors = new();
    private List<string> timeSlots = new();

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();

        // Validate step 1 fields only
        var isValid = true;
        var step1Fields = new[] { nameof(model.PatientName), nameof(model.Email), nameof(model.Phone), nameof(model.InsuranceProvider) };
        foreach (var field in step1Fields)
        {
            var fieldIdentifier = editContext!.Field(field);
            editContext.NotifyFieldChanged(fieldIdentifier);
            if (editContext.GetValidationMessages(fieldIdentifier).Any())
            {
                isValid = false;
            }
        }

        if (!isValid) return;

        // Run server-side validation
        var errors = await AppointmentService.ValidatePatientAsync(
            model.Email!, model.InsuranceProvider!, model.Doctor ?? "", model.TimeSlot ?? "");

        // Only show step-1-relevant errors at this stage
        var step1Errors = errors
            .Where(e => e.Key == nameof(model.Email))
            .ToDictionary(e => e.Key, e => e.Value);

        if (step1Errors.Count > 0)
        {
            customValidator!.DisplayErrors(step1Errors);
            return;
        }

        showStep2 = true;
    }

    private async Task OnDoctorOrDateChanged()
    {
        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                model.Doctor, model.AppointmentDate.Value);
            model.TimeSlot = null;
        }
    }

    private async Task HandleSubmit()
    {
        customValidator?.ClearErrors();

        // Validate future date
        if (model.AppointmentDate.HasValue && model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            customValidator!.DisplayErrors(new Dictionary<string, List<string>>
            {
                [nameof(model.AppointmentDate)] = ["Date must be in the future."]
            });
            return;
        }

        isSubmitting = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                model.Email!, model.InsuranceProvider!, model.Doctor!, model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            bookingConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

